  Future<void> _cleanupTableIfInactive() async {
    try {
      final playerRows = await _supabase
          .from('table_players')
          .select('user_id')
          .eq('table_id', widget.tableId);
      final players = (playerRows as List)
          .map((e) => Map<String, dynamic>.from(e as Map))
          .toList();

      bool inactive = players.isEmpty;
      if (!inactive) {
        final ids = players
            .map((p) => p['user_id']?.toString())
            .whereType<String>()
            .where((id) => id.isNotEmpty)
            .toList();
        if (ids.isEmpty) {
          inactive = true;
        } else {
          final users = await _supabase
              .from('users')
              .select('id,is_bot')
              .inFilter('id', ids);
          final isBotById = <String, bool>{
            for (final raw in (users as List))
              (raw['id']?.toString() ?? ''): raw['is_bot'] == true,
          };
          final hasHuman = ids.any((id) => isBotById[id] != true);
          inactive = !hasHuman;
        }
      }

      if (!inactive) return;

      try {
        await _supabase
            .from('match_moves')
            .delete()
            .eq('table_id', widget.tableId);
      } catch (_) {}
      try {
        await _supabase
            .from('table_discard_tops')
            .delete()
            .eq('table_id', widget.tableId);
      } catch (_) {}
      try {
        await _supabase
            .from('table_discards')
            .delete()
            .eq('table_id', widget.tableId);
      } catch (_) {}
      try {
        await _supabase
            .from('table_players')
            .delete()
            .eq('table_id', widget.tableId);
      } catch (_) {}
      try {
        await _supabase.from('tables').delete().eq('id', widget.tableId);
      } catch (_) {}
    } catch (_) {}
  }
  Future<void> _toggleDoubleMode() async {
    if (_doubleMode) {
      _showSnack('\u00C7ifte git se\u00E7imi geri al\u0131namaz.');
      return;
    }

    final ok = await showDialog<bool>(
      context: context,
      builder: (context) => AlertDialog(
        title: const Text('\u00C7ifte Git'),
        content: const Text(
          '\u00C7ifte gidersen bu karar\u0131 geri alamazs\u0131n ve elde \u00E7iftten bitmek zorundas\u0131n. Onayl\u0131yor musun?',
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(context, false),
            child: const Text('Hay\u0131r'),
          ),
          FilledButton(
            onPressed: () => Navigator.pop(context, true),
            child: const Text('Evet'),
          ),
        ],
      ),
    );

    if (ok != true) return;

    setState(() => _doubleMode = true);

    final userId = _myUserId;
    if (userId == null) return;
    try {
      await _supabase
          .from('table_players')
          .update({'is_double_mode': true})
          .eq('table_id', widget.tableId)
          .eq('user_id', userId);
    } catch (_) {
      // optional column, ignore
    }
  }

  void _showFinishMessage(String text) {
    _finishFxText = text;
    _showFinishFx = true;
    if (mounted) setState(() {});
    Timer(const Duration(seconds: 3), () {
      if (!mounted) return;
      setState(() => _showFinishFx = false);
    });
  }

  DateTime? _parseServerTime(dynamic raw) {
    if (raw == null) return null;
    final parsed = DateTime.tryParse(raw.toString());
    if (parsed == null) return null;
    return parsed.toLocal();
  }

  int get _joinCountdown {
    if (_tableStatus != 'waiting' || _playerCount < _maxPlayers) return 0;
    if (_readySince == null) return 5;
    final elapsed = DateTime.now().difference(_readySince!).inSeconds;
    final remain = 5 - elapsed;
    if (remain <= 0) return 0;
    return remain;
  }

